      "english": "{0:When} {5:this one} — the {8:ascetic} {7:engaged} {6:in the steadiness of knowledge} — {1:draws in} {2:fully}, {3:that is, withdraws} {4:as well}, just as {9:a tortoise draws in} {10:its limbs}{11:}: {12:just as} {13:a tortoise} {14:out of fear} {17:draws in} {15:its own} {16:limbs} {18:from every side}, {19:on all sides}, {20:so} {21:the one steadfast in knowledge} {25:draws in} {22:the indriyas} {23:from their objects}, {24:from all the spheres of sense}. {26:‘His} {27:prajñā} {28:stands firm’} {29:—} {31:the sentence} {30:whose meaning has already been stated}.",
